  (579, 'fotos', '2166.jpg', 'Gun''s N Roses y The Rolling Stones', ARRAY['Slash', 'Steven Adler', 'Axl Rose', 'Duff McKagan', 'Izzy Stradlin', 'Keith Richards', 'Charlie Watts', 'Mick Jagger']::text[], 1989, null, 'Facebook', null, null::date, null, null, null),
  (580, 'fotos', '2167.jpg', 'Cuadrillas', ARRAY['Eric Clapton', 'Mark Knopfler', 'Phil Collins', 'Paul McCartney', 'George Martin']::text[], 1997, null, 'Facebook', null, null::date, null, null, null),
  (581, 'fotos', '2168.jpg', 'Little Richard', ARRAY[]::text[], null, null, 'Facebook', 'Decía David Bowie que Little Richard era la figura más influyente en la música del siglo XX.  Su influencia sobre los Beatles, Rolling Stones o el propio Bowie, es reconocida por ellos mismos, y no solo se refería a la música, ¿el look de Prince? ¿De donde creéis que salió? Aquellos trajes recargados del Glam. El primero en quitarse la camiseta tocando. James Brown y Jimmy Hendrix tocaron en su banda y en 1962, en su primera gran gira por Inglaterra, sus conciertos se convertían en autenticas batallas campales entre la policía y los jovenes chavales británicos, que se volvían completamente locos con su musica, arrancando los asientos de las salas de conciertos, todo ello 15 años antes de que llegara el Punk. Little Richard era el Punk antes de que existiera el Punk, Little Richard era el Rock"N"Roll, Little Richard es un dios en esta casa. Negro, Homosexual y con una discapacidad en la pierna en el sur profundo, en la America de los 50’s, tuvo que soportar que sus éxitos vendieran más discos cantados por blancos como Elvis o el ridículo Pat Boone. Little Richard es la figura más influyente de la música en el siglo XX, por eso a nosotrs nos gusta abrir con él periódicamente y recordar su historia o contarla a quien llega nuevo o nueva. Hoy, "Dancing All Around The World". Viva Little Richard!!!', null::date, null, null, null),
  (582, 'fotos', '2169.jpg', 'Kortatu', ARRAY['Iñigo Muguruza', 'Fermin Muguruza']::text[], 1985, (select id from public.grupos where nombre = 'Kortatu' limit 1), 'Facebook', null, null::date, null, null, null),
