  (776, 'fotos', '2363.jpg', 'Charly Garcia', ARRAY['Charly Garcia']::text[], null, null, 'Facebook', 'Se juntó todo en un petisito que tenía mucha polenta. Tocaba la guitarra de una forma muy rara; era un mal buen guitarrista. Tocaba como si tocara folklore. Vos ves tocar a George Harrison, a Cafrune y al de Nirvana, y te vas a dar cuenta que Cobain toca como Cafrune. Las posiciones ortodoxas: la Mayor poniendo los tres deditos acá, el mi Mayor así... Jamás escuchó jazz en su vida, ni quiere saber lo que es una séptima. Eso me parece bueno. Es raro, por eso llamaba la atención. Y como cantante es buenísimo. La fonética del tipo es muy musical, tiene algo johnlennonesco en el rango de voz. O sea: es buenísimo en todo, ¿qué querés que te diga? ¡Es mejor que yo, lo siento!', null::date, null, null, null),
  (777, 'fotos', '2364.jpg', 'The Beatles', ARRAY['Paul McCartney', 'John Lennon', 'George Harrison', 'Ringo Star', 'Ed Sullivan']::text[], 1964, (select id from public.grupos where nombre = 'The Beatles' limit 1), 'Facebook', 'El 9 de febrero de 1964 Los Beatles actuaron para setenta millones de personas en Estados Unidos en el show del presentador estadounidense Ed Sullivan. Esa noche los chicos de Liverpool cambiaron la cultura popular y su legado permanente intacto hasta nuestros días', null::date, null, null, null),
