  (2587, 'fotos', '4182.jpg', 'Mick Jagger y James Brown', ARRAY['Mick Jagger', 'James Brown']::text[], null, null, 'Facebook', null, null::date, null, null, null),
  (2588, 'fotos', '4183.jpg', 'The Rolling Stones y James Brown', ARRAY['Mick Jagger', 'Keith Richards', 'James Brown', 'Brian Jones']::text[], null, null, 'Facebook', null, null::date, null, null, null),
  (2589, 'fotos', '4184.jpg', 'David Byrne en el CBGB', ARRAY['David Byrne']::text[], 1977, (select id from public.grupos where nombre = 'Talking Heads' limit 1), 'Facebook', null, null::date, null, null, null),
