),
deduped as (
  select distinct on (bucket, imagen)
    bucket,
    imagen,
    titulo,
    personas,
    anio,
    grupo_id,
    origen,
    descripcion,
    fecha,
    lugar,
    categoria,
    concierto_id
  from source
  order by bucket, imagen, ord desc
)
insert into public.fotos (
  bucket,
  imagen,
  titulo,
  personas,
  anio,
  grupo_id,
  origen,
  descripcion,
  fecha,
  lugar,
  categoria,
  concierto_id
)
select
  bucket,
  imagen,
  titulo,
  personas,
  anio,
  grupo_id,
  origen,
  descripcion,
  fecha,
  lugar,
  categoria,
  concierto_id
from deduped
on conflict (bucket, imagen) do update
set
  titulo = excluded.titulo,
  personas = excluded.personas,
  anio = excluded.anio,
  grupo_id = excluded.grupo_id,
  origen = excluded.origen,
  descripcion = excluded.descripcion,
  fecha = excluded.fecha,
  lugar = excluded.lugar,
  categoria = excluded.categoria,
  concierto_id = excluded.concierto_id;

commit;
